#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        // use a simple hash table via sorting for deterministic O(N log N) which is safe for constraints
        int *a = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), (int(*)(const void*,const void*))strcmp);
        int ok = 1;
        for(int i=1;i<N;i++) if(a[i]==a[i-1]){ ok=0; break; }
        printf(ok?"YES\n":"NO\n");
        free(a);
    }
    return 0;
}

